//! Expression type inference.

use tc24r_ast::{BinOp, Expr, Type};
use tc24r_codegen_state::CodegenState;

/// Infer the type of an expression from codegen state.
///
/// Returns `None` for expressions whose type cannot be determined
/// (e.g., integer literals, function calls without return-type tracking).
pub fn expr_type(state: &CodegenState, expr: &Expr) -> Option<Type> {
    match expr {
        Expr::Ident(name) => {
            let ty = state
                .local_types
                .get(name)
                .or_else(|| state.global_types.get(name))
                .cloned()?;
            // Array decays to pointer to element
            match ty {
                Type::Array(inner, _) => Some(Type::Ptr(inner)),
                other => Some(other),
            }
        }
        Expr::Cast { ty, .. } => Some(ty.clone()),
        Expr::AddrOf(name) => {
            let inner = expr_type(state, &Expr::Ident(name.clone()))?;
            Some(Type::Ptr(Box::new(inner)))
        }
        Expr::Deref(inner) => match expr_type(state, inner)? {
            Type::Ptr(pointee) => Some(*pointee),
            _ => None,
        },
        Expr::StringLit(_) => Some(Type::Ptr(Box::new(Type::Char))),
        Expr::BinOp {
            op: BinOp::Add,
            lhs,
            ..
        }
        | Expr::BinOp {
            op: BinOp::Sub,
            lhs,
            ..
        } => {
            // Pointer arithmetic preserves pointer type
            let lhs_ty = expr_type(state, lhs)?;
            if matches!(lhs_ty, Type::Ptr(_)) {
                Some(lhs_ty)
            } else {
                None
            }
        }
        _ => None,
    }
}

//! Expression AST nodes.

/// An expression node.
#[derive(Debug)]
pub enum Expr {
    IntLit(i32),
    StringLit(String),
    Ident(String),
    Assign {
        name: String,
        value: Box<Expr>,
    },
    Call {
        name: String,
        args: Vec<Expr>,
    },
    /// Indirect call through expression: expr(args)
    IndirectCall {
        callee: Box<Expr>,
        args: Vec<Expr>,
    },
    BinOp {
        op: BinOp,
        lhs: Box<Expr>,
        rhs: Box<Expr>,
    },
    UnaryOp {
        op: UnaryOp,
        operand: Box<Expr>,
    },
    /// Address-of: &x
    AddrOf(String),
    /// Pointer dereference: *p
    Deref(Box<Expr>),
    /// Cast expression: (type)expr
    Cast {
        ty: crate::Type,
        expr: Box<Expr>,
    },
    /// Dereference assignment: *p = val
    DerefAssign {
        ptr: Box<Expr>,
        value: Box<Expr>,
    },
    /// Pre-increment: ++i (returns new value)
    PreInc(String),
    /// Pre-decrement: --i (returns new value)
    PreDec(String),
    /// Post-increment: i++ (returns old value)
    PostInc(String),
    /// Post-decrement: i-- (returns old value)
    PostDec(String),
    /// Struct member access: expr.member
    MemberAccess {
        object: Box<Expr>,
        member: String,
    },
    /// Struct member assignment: expr.member = value
    MemberAssign {
        object: Box<Expr>,
        member: String,
        value: Box<Expr>,
    },
    /// GCC statement expression: ({ stmt1; stmt2; expr; })
    StmtExpr(crate::Block),
    /// Ternary: cond ? then_expr : else_expr
    Ternary {
        cond: Box<Expr>,
        then_expr: Box<Expr>,
        else_expr: Box<Expr>,
    },
}

/// Binary operator.
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum BinOp {
    Add,
    Sub,
    Mul,
    Div,
    Mod,
    BitAnd,
    BitOr,
    BitXor,
    Shl,
    Shr,
    Eq,
    Ne,
    Lt,
    Gt,
    Le,
    Ge,
    LogAnd,
    LogOr,
    Comma,
}

/// Unary operator.
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum UnaryOp {
    Neg,
    BitNot,
    LogNot,
}

