13	/// Parse an expression (includes comma operator at lowest precedence).
14	pub fn parse_expr(ts: &mut TokenStream) -> Result<Expr, CompileError> {
15	    let mut lhs = parse_assign(ts)?;
16	    while ts.eat(TokenKind::Comma) {
17	        let rhs = parse_assign(ts)?;
18	        lhs = Expr::BinOp {
19	            op: BinOp::Comma,
20	            lhs: Box::new(lhs),
21	            rhs: Box::new(rhs),
22	        };
23	    }
24	    Ok(lhs)
25	}
