27	/// Parse an assignment expression (used in function args, initializers).
28	pub fn parse_assign(ts: &mut TokenStream) -> Result<Expr, CompileError> {
29	    let expr = parse_ternary(ts)?;
30	    if ts.eat(TokenKind::Assign) {
31	        let value = parse_assign(ts)?;
32	        return make_assign(expr, value);
33	    }
34	    if let Some(op) = eat_compound_assign(ts) {
35	        let rhs = parse_assign(ts)?;
36	        return desugar_compound(expr, op, rhs);
