41	fn parse_ternary(ts: &mut TokenStream) -> Result<Expr, CompileError> {
42	    let cond = parse_log_or(ts)?;
43	    if ts.eat(TokenKind::Question) {
44	        let then_expr = parse_expr(ts)?;
45	        ts.expect(TokenKind::Colon)?;
46	        let else_expr = parse_ternary(ts)?;
47	        return Ok(Expr::Ternary {
48	            cond: Box::new(cond),
49	            then_expr: Box::new(then_expr),
50	            else_expr: Box::new(else_expr),
51	        });
52	    }
53	    Ok(cond)
54	}
55	
56	pub fn parse_unary(ts: &mut TokenStream) -> Result<Expr, CompileError> {
57	    if ts.eat(TokenKind::Sizeof) {
58	        return parse_sizeof(ts);
59	    }
60	    if ts.eat(TokenKind::Offsetof) {
61	        return parse_offsetof(ts);
62	    }
63	    if ts.eat(TokenKind::Plus) {
64	        // Unary + is identity, just parse the operand
65	        return parse_unary(ts);
66	    }
67	    if ts.eat(TokenKind::Minus) {
68	        let operand = parse_unary(ts)?;
69	        return Ok(Expr::UnaryOp {
70	            op: UnaryOp::Neg,
71	            operand: Box::new(operand),
72	        });
73	    }
74	    if ts.eat(TokenKind::Tilde) {
75	        let operand = parse_unary(ts)?;
76	        return Ok(Expr::UnaryOp {
77	            op: UnaryOp::BitNot,
78	            operand: Box::new(operand),
79	        });
80	    }
81	    if ts.eat(TokenKind::Bang) {
82	        let operand = parse_unary(ts)?;
83	        return Ok(Expr::UnaryOp {
84	            op: UnaryOp::LogNot,
85	            operand: Box::new(operand),
86	        });
87	    }
88	    if ts.eat(TokenKind::PlusPlus) {
89	        let name = ts.expect_ident()?;
90	        return Ok(Expr::PreInc(name));
91	    }
92	    if ts.eat(TokenKind::MinusMinus) {
93	        let name = ts.expect_ident()?;
94	        return Ok(Expr::PreDec(name));
95	    }
96	    if ts.eat(TokenKind::Amp) {
97	        let name = ts.expect_ident()?;
98	        // Check for postfix: &arr[i], &s.field, etc.
99	        if ts.check(&TokenKind::LBracket)
100	            || ts.check(&TokenKind::Dot)
101	            || ts.check(&TokenKind::Arrow)
102	        {
103	            let base = Expr::Ident(name);
104	            let postfix = parse_postfix_chain(ts, base)?;
105	            // &arr[i] is equivalent to arr + i (pointer arithmetic),
106	            // and arr[i] is already desugared to *(arr + i) by parse_postfix_chain.
107	            // So &*(arr + i) simplifies to (arr + i). Extract the inner expr from Deref.
108	            if let Expr::Deref(inner) = postfix {
109	                return Ok(*inner);
110	            }
111	            // For &s.field or &s->field, wrap in AddrOf-like expression.
112	            // These are member access on a local — the address is computable.
113	            return Ok(Expr::AddrOf(String::new())); // fallback (shouldn't reach)
114	        }
115	        return Ok(Expr::AddrOf(name));
116	    }
117	    if ts.eat(TokenKind::Star) {
118	        let operand = parse_unary(ts)?;
119	        return Ok(Expr::Deref(Box::new(operand)));
120	    }
121	    parse_primary(ts)
122	}
123	
124	fn parse_primary(ts: &mut TokenStream) -> Result<Expr, CompileError> {
125	    if ts.eat(TokenKind::LParen) {
126	        // Statement expression: ({ stmt; ... expr; })
127	        if ts.check(&TokenKind::LBrace) {
128	            let block = parse_block(ts)?;
129	            ts.expect(TokenKind::RParen)?;
130	            return parse_postfix_chain(ts, Expr::StmtExpr(block));
131	        }
132	        // Cast: (type)expr  vs  parenthesized: (expr)
133	        if is_type_start(ts) {
134	            let ty = parse_type(ts)?;
135	            ts.expect(TokenKind::RParen)?;
136	            let operand = parse_unary(ts)?;
137	            let cast = Expr::Cast {
138	                ty,
139	                expr: Box::new(operand),
140	            };
141	            return parse_postfix_chain(ts, cast);
142	        }
143	        let expr = parse_expr(ts)?;
144	        ts.expect(TokenKind::RParen)?;
145	        return parse_postfix_chain(ts, expr);
146	    }
147	    if let TokenKind::IntLit(_) = &ts.peek().kind {
148	        let TokenKind::IntLit(val) = ts.advance().kind else {
149	            unreachable!()
150	        };
151	        return Ok(Expr::IntLit(val));
152	    }
153	    if let TokenKind::StringLit(_) = &ts.peek().kind {
154	        let TokenKind::StringLit(mut s) = ts.advance().kind else {
155	            unreachable!()
156	        };
157	        // C89 implicit string literal concatenation: "a" "b" → "ab"
158	        while let TokenKind::StringLit(_) = &ts.peek().kind {
159	            let TokenKind::StringLit(next) = ts.advance().kind else {
160	                unreachable!()
161	            };
162	            s.push_str(&next);
163	        }
164	        return Ok(Expr::StringLit(s));
165	    }
166	    if let TokenKind::Ident(_) = &ts.peek().kind {
167	        return parse_ident_or_call(ts);
168	    }
169	    Err(CompileError::new(
170	        format!("expected expression, got {:?}", ts.peek().kind),
171	        Some(ts.current_span()),
172	    ))
173	}
174	
175	fn parse_ident_or_call(ts: &mut TokenStream) -> Result<Expr, CompileError> {
176	    let TokenKind::Ident(name) = ts.advance().kind else {
177	        unreachable!()
178	    };
179	    // Resolve enum constants to integer literals
180	    if let Some(&val) = ts.enum_constants.get(&name) {
181	        return Ok(Expr::IntLit(val));
182	    }
183	    // Function call: foo(args...)
184	    if ts.eat(TokenKind::LParen) {
185	        let mut args = Vec::new();
186	        if !ts.check(&TokenKind::RParen) {
187	            loop {
188	                args.push(parse_assign(ts)?);
189	                if !ts.eat(TokenKind::Comma) {
190	                    break;
191	                }
192	            }
193	        }
194	        ts.expect(TokenKind::RParen)?;
195	        let call = Expr::Call { name, args };
196	        return parse_postfix_chain(ts, call);
197	    }
198	    // Postfix ++/-- (these consume the name, not chainable)
199	    if ts.eat(TokenKind::PlusPlus) {
200	        return Ok(Expr::PostInc(name));
201	    }
202	    if ts.eat(TokenKind::MinusMinus) {
203	        return Ok(Expr::PostDec(name));
204	    }
205	    // Start with the identifier, then chain postfix ops: [], ., ->
206	    let mut result = Expr::Ident(name);
207	    result = parse_postfix_chain(ts, result)?;
208	    Ok(result)
209	}
210	
211	/// Parse chained postfix operations: a[i].b->c[j] etc.
212	fn parse_postfix_chain(ts: &mut TokenStream, mut expr: Expr) -> Result<Expr, CompileError> {
213	    loop {
214	        if ts.eat(TokenKind::LBracket) {
215	            let index = parse_expr(ts)?;
216	            ts.expect(TokenKind::RBracket)?;
217	            expr = Expr::Deref(Box::new(Expr::BinOp {
218	                op: tc24r_ast::BinOp::Add,
219	                lhs: Box::new(expr),
220	                rhs: Box::new(index),
221	            }));
222	        } else if ts.eat(TokenKind::LParen) {
223	            // Indirect call: expr(args) — for table[n](arg), (*fp)(arg), etc.
224	            let mut args = Vec::new();
225	            if !ts.check(&TokenKind::RParen) {
226	                loop {
227	                    args.push(parse_assign(ts)?);
228	                    if !ts.eat(TokenKind::Comma) {
229	                        break;
230	                    }
231	                }
232	            }
233	            ts.expect(TokenKind::RParen)?;
234	            expr = Expr::IndirectCall {
235	                callee: Box::new(expr),
236	                args,
237	            };
238	        } else if ts.eat(TokenKind::Dot) {
239	            let member = ts.expect_ident()?;
240	            expr = Expr::MemberAccess {
241	                object: Box::new(expr),
242	                member,
243	            };
244	        } else if ts.eat(TokenKind::Arrow) {
245	            let member = ts.expect_ident()?;
246	            expr = Expr::MemberAccess {
247	                object: Box::new(Expr::Deref(Box::new(expr))),
248	                member,
249	            };
250	        } else {
251	            break;
252	        }
253	    }
254	    Ok(expr)
255	}
256	
257	/// Parse `sizeof(type)` or `sizeof(expr)` after the `sizeof` token.
258	fn parse_sizeof(ts: &mut TokenStream) -> Result<Expr, CompileError> {
259	    ts.expect(TokenKind::LParen)?;
260	    if is_type_start(ts) {
261	        let mut ty = parse_type(ts)?;
262	        // Handle array suffix: sizeof(int[4]), sizeof(char[16])
263	        while ts.eat(TokenKind::LBracket) {
264	            let TokenKind::IntLit(size) = ts.peek().kind else {
265	                return Err(CompileError::new(
266	                    "expected array size in sizeof",
267	                    Some(ts.current_span()),
268	                ));
269	            };
270	            ts.advance();
271	            ts.expect(TokenKind::RBracket)?;
272	            ty = Type::Array(Box::new(ty), size as usize);
273	        }
274	        ts.expect(TokenKind::RParen)?;
275	        return Ok(Expr::IntLit(ty.size()));
276	    }
277	    // sizeof(expr) -- no type info available, assume int-sized
278	    let _expr = parse_unary(ts)?;
279	    ts.expect(TokenKind::RParen)?;
280	    Ok(Expr::IntLit(3))
281	}
282	
283	/// Parse `offsetof(type, member)` after the `offsetof` token.
284	fn parse_offsetof(ts: &mut TokenStream) -> Result<Expr, CompileError> {
285	    ts.expect(TokenKind::LParen)?;
286	    let ty = parse_type(ts)?;
287	    ts.expect(TokenKind::Comma)?;
288	    let member = ts.expect_ident()?;
289	    ts.expect(TokenKind::RParen)?;
290	    match ty.find_member(&member) {
291	        Some(m) => Ok(Expr::IntLit(m.offset)),
292	        None => Err(CompileError::new(
293	            format!("no member '{member}' in type"),
294	            Some(ts.current_span()),
295	        )),
296	    }
297	}
